1	const PROCESSING_FEE = 5;
2	const COMPONENT_BASE_PREMIUM = 25;
3	const COMPONENT_BLOCK_SIZE = 3;
4	const COMPONENT_BLOCK_PREMIUM = 60;
5	
6	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	};
12	
13	type Item = { type: string };
14	type Step = { op: "quote"; items: Item[] };
15	type Scenario = { customer: unknown; steps: Step[] };
16	
17	const componentGroupPremium = (count: number): number =>
18	  count === COMPONENT_BLOCK_SIZE
19	    ? COMPONENT_BLOCK_PREMIUM
20	    : count * COMPONENT_BASE_PREMIUM;
21	
22	const groupPremium = (type: string, count: number): number =>
23	  type in BASE_PREMIUM_BY_TYPE
24	    ? count * BASE_PREMIUM_BY_TYPE[type]
25	    : componentGroupPremium(count);
26	
27	const countByType = (items: Item[]): Map<string, number> =>
28	  items.reduce(
29	    (counts, { type }) => counts.set(type, (counts.get(type) ?? 0) + 1),
30	    new Map<string, number>(),
31	  );
32	
33	const sumBasePremiums = (items: Item[]): number =>
34	  [...countByType(items).entries()]
35	    .reduce((sum, [type, count]) => sum + groupPremium(type, count), 0);
36	
37	const quotePremiumFor = (step: Step): { premium: number } => ({
38	  premium: sumBasePremiums(step.items) + PROCESSING_FEE,
39	});
40	
41	export const runScenario = (scenario: Scenario): { results: unknown[] } => ({
42	  results: scenario.steps.map(quotePremiumFor),
43	});
